{
  "summary": "This paper proposes a method to automatically create noisy parallel datasets for code translation by leveraging classical document similarity metrics, particularly Word Movers Distance, to pair code samples across programming languages. The approach enables supervised training of code translation models for multiple language pairs without manual curation, demonstrating robustness to noise and improved performance over random pairing baselines.",
  "strengths": [
    {
      "point": "Effective use of document similarity metrics to create noisy parallel datasets",
      "evidence": "WMD consistently achieved the highest match accuracy (~90%) on known datasets and outperformed other metrics on CodeNet pseudo-match accuracy."
    },
    {
      "point": "Demonstrated noise tolerance of code translation models",
      "evidence": "Models trained on noisy datasets showed gradual performance degradation with increasing noise but remained significantly better than random baselines."
    },
    {
      "point": "Expanded supervised code translation to 10 language pairs beyond prior work",
      "evidence": "Created and released noisy parallel datasets for 10 languages and showed improved computational accuracy @ 5 over random pairing for multiple language pairs."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent neural embedding alignment or code representation learning methods",
      "evidence": "The paper does not compare against advanced embedding-based similarity methods such as contrastive learning or multilingual code embeddings."
    },
    {
      "point": "Insufficient justification and analysis of similarity threshold and pairing constraints",
      "evidence": "No principled method or ablation study for choosing similarity threshold δ or rationale for forbidding multiple pairings of the same document."
    },
    {
      "point": "Limited evaluation metrics and missing comparison to unsupervised code translation models",
      "evidence": "Evaluation relies on BLEU, CodeBLEU, EM, and CA@k without manual code review or semantic equivalence metrics; no direct comparison to state-of-the-art unsupervised models."
    },
    {
      "point": "Reproducibility concerns due to missing preprocessing details and partial dataset release",
      "evidence": "Preprocessing steps like tokenization are not specified, and it is unclear which dataset subsets are released or how to reconstruct full noisy datasets."
    },
    {
      "point": "Lack of discussion on language-specific challenges, code context, and generalizability",
      "evidence": "No analysis of how syntax or idioms affect similarity matching; method ignores project context and dependencies; unclear performance on industrial or low-resource codebases."
    },
    {
      "point": "Ambiguity in defining and quantifying noise in created datasets",
      "evidence": "The term 'noisy' is used without clear definition or quantification beyond approximate error rates."
    },
    {
      "point": "Insufficient explanation of Word Movers Distance adaptation to code tokens",
      "evidence": "The paper lacks detailed explanation of how WMD is computed on code tokens, which differ from natural language."
    }
  ],
  "questions": [
    {
      "question": "How would the proposed method compare to recent neural embedding alignment or multilingual code representation learning approaches?",
      "motivation": "Understanding this would clarify the novelty and potential performance gains over classical similarity metrics."
    },
    {
      "question": "How sensitive are results to the similarity threshold δ and the constraint forbidding multiple pairings of the same document?",
      "motivation": "This affects reproducibility, robustness, and dataset coverage, impacting practical applicability."
    },
    {
      "question": "Can the method scale and generalize to large-scale industrial codebases or low-resource/domain-specific languages?",
      "motivation": "This determines the broader impact and usability of the approach beyond academic datasets."
    },
    {
      "question": "What preprocessing steps are necessary to reproduce similarity computations and model training?",
      "motivation": "Detailed preprocessing is crucial for replicating results and building upon this work."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
